    'compare.supVsRib.col2Title': 'Knit Fabric',
    'compare.supVsRib.propulsion': 'Durability:',
    'compare.supVsRib.supPropDesc': 'Excellent UV resistance. Good abrasion resistance. Low moisture absorption (0.4%). Dries quickly.',
    'compare.supVsRib.portability': 'Moisture Management:',
    'compare.supVsRib.cost': 'Cost:',
    'compare.supVsRib.supPortDesc': 'Hydrophobic fibers wick moisture effectively. Quick-drying performance ideal for activewear and outdoor gear.',
    'compare.supVsRib.supCostDesc': '$0.80-$2.50 per yard. Most cost-effective synthetic fiber. High availability in global markets.',
    'compare.supVsRib.fitness': 'Applications:',
    'compare.supVsRib.supFitDesc': 'Sportswear, outdoor gear, home textiles, medical textiles, industrial fabrics, luggage fabrics.',
