    'oem.stat4': 'Pays d\'exportation',
    'oem.why': 'Pourquoi s\'associer à Seekingtex pour l\'OEM/ODM ?',
    'oem.para1': 'Seekingtex n\'est pas une société de négoce. Nous sommes la division manufacturing de Qingdao Vatrad Group →un groupe industriel chinois verticalement intégré avec 12 000 m² d\'espace de production et une capacité annuelle de 15 000+ unités.',
    'oem.certs': 'Certifications Internationales',
    'oem.ctaTitle': 'Prêt à lancer votre projet OEM ?',
    'oem.ctaSub': 'Parlez-nous de vos besoins. Nous répondrons avec un devis détaillé et un délai sous 24 heures.',
    'oem.moq': 'MOQ 5? unités (SUP/kayak), 2?unités (RIB). FOB Qingdao.',
    'oemProcess.title': 'Processus de Fabrication OEM/ODM →De la Demande à la Production',
    'oemProcess.desc': 'Processus complet de fabrication OEM/ODM avec Seekingtex. Étape par étape : demande, spécification, conception de moule, production d\'échantillons, conformité CE, production en série et expédition FOB. Usine de 12 000 m² .',
    'oemProcess.badge': 'Processus OEM/ODM',
    'oemProcess.heading': 'De la Demande à la Production',
    'oemProcess.subtitle': 'Processus de fabrication de bout en bout pour embarcations gonflables. Certifié CE, , FOB Qingdao.',
    'oemProcess.cta': 'Lancer votre projet',
    'oemProcess.ctaTitle': 'Prêt à lancer votre projet OEM ?',
