    'engineeringPerfection.rel4': 'التصميم والابتكار',
    'engineeringPerfection.rel4desc': 'استوديو تصميم متكامل لمشاريع ODM المخصصة، من المفهوم إلى الإنتاج.',
    'disasterRelief.nav': 'الإغاثة من الكوارث والمساعدات الإنسانية',
    'disasterRelief.badge': 'المهمات الإنسانية',
