    'searchRescue.nav': 'Søk og redning',
    'searchRescue.badge': 'SAR-løsninger',
    'searchRescue.heading': 'Søk og redning',
    'searchRescue.subtitle': 'Seekingtex oppblåsbare båter er konstruert for de kompromissløse kravene til søk og redning. Uten rom for feil leverer våre farkoster urokkelig pålitelighet, overlegen ytelse og absolutt sikkerhet i de mest farlige miljøene.',
    'searchRescue.s1': 'Avanserte materialer for SAR-applikasjoner',
    'searchRescue.s1desc': 'Grunnlaget for enhver pålitelig SAR oppblåsbar båt ligger i kvaliteten på konstruksjonsmaterialene. Seekingtex bruker Hypalon (CSM/Neopren), avansert PVC og banebrytende TPU-stoffer ?hvert valgt for optimal holdbarhet under ekstreme forhold. Våre stoffer tilbyr overlegen UV-motstand, kjemisk motstandsdyktighet og slitasjebeskyttelse, og sikrer at farkosten din fungerer feilfritt oppdrag etter oppdrag.',
    'searchRescue.s2': 'Designprinsipper for optimal SAR-ytelse',
    'searchRescue.s2desc': 'Hver Seekingtex SAR-båt har avanserte V-keel-design for retningsstabilitet og overlegne multi-kammer flyttesystemer med 3? uavhengige luftrom. Hvis ett kammer kompromitteres, beholder de gjenværende kamrene full oppblåsing ?holder deg operasjonell og trygg. Våre skrogdesign prioriterer stabilitet, manøvrerbarhet og tilgang til grunne farvann, avgjørende for redningsmiljøer.',
    'searchRescue.s3': 'Spesialisert utstyr og tilbehør',
    'searchRescue.s3desc': 'Seekingtex-båter er konstruert som tilpasningsdyktige plattformer for varierte SAR-oppdrag. Funksjoner inkluderer selvrettende systemkompatibilitet, forsterkede slepepunkter, lave fribord-soner for å redde ofre, ergonomiske konsoll-design for GPS/VHF-integrasjon, og SOLAS-grade reflekterende merkinger for maksimal synlighet.',
    'searchRescue.s4': 'Ukompromittert produksjonsprosess',
    'searchRescue.s4desc': 'Vår produksjon bruker termosveising (for PVC/TPU) og presis håndliming (for Hypalon) i klimakontrollerte miljøer. Hver båt gjennomgår en 24?2 timers trykktest, individuell ventiltesting, sømstyrkeverifisering og omfattende dimensjonssjekker før frakt.',
    'searchRescue.f1desc': 'Redundant flyteevne for maksimal sikkerhet',
    'searchRescue.f2desc': 'Høy synlighet for natt-operasjoner',
    'searchRescue.f3desc': 'Rask vanntapping',
    'searchRescue.f4desc': 'Tungbruks D-ringer i rustfritt stål',
    'searchRescue.f5': 'Sveisede sømmer',
    'searchRescue.f5desc': 'Molekylær binding ?sterkere enn stoffet selv',
    'searchRescue.f6': '24?2 timers trykktest',
    'searchRescue.f6desc': 'Hver båt testet før frakt',
    'searchRescue.ctaTitle': 'Bygget for de som redder liv',
    'searchRescue.ctaSub': 'Å velge Seekingtex er en investering i tillit ?tillit til farkostens integritet, dens operasjonelle yteevne, og dens evne til å fungere feilfritt når menneskeliv står på spill. Våre båter er betrodde partnere i den edle bestrebelsen å redde liv.',
    'searchRescue.cta': 'Be om SAR-spesifikasjoner',
    'searchRescue.expTitle': 'Hvordan våre båter presterer i ekte oppdrag',
    'searchRescue.expSub': 'Første-hånds beretninger fra SAR-team og operatører som stoler på Seekingtex-båter i feltet.',
    'searchRescue.relatedTitle': 'Relaterte ressurser',
    'searchRescue.relatedSub': 'Utforsk mer om Seekingtex SAR-kapasiteter og produksjon',
    'searchRescue.rel1': 'Katastrofehjelp og humanitær bistand',
    'searchRescue.rel2': 'Kommersielle arbeidsbåter',
    'searchRescue.rel2desc': 'Holdbare RIB-er og arbeidsbåter for daglige kommersielle marine operasjoner.',
    'searchRescue.rel3': 'Ingeniørperfeksjon',
    'searchRescue.rel3desc': 'Vår ingeniør-filosofi ?presis produksjon og grundig kvalitetskontroll.',
