    'disasterRelief.expSub': 'Hvordan Seekingtex oppblåsbare båter støtter katastrofeberedskap og humanitære bistandsoppdrag over hele verden.',
    'disasterRelief.relatedTitle': 'Relaterte ressurser',
    'disasterRelief.relatedSub': 'Utforsk mer om Seekingtex humanitære og katastrofeberedskaps-kapasiteter',
    'disasterRelief.rel1': 'Søk og redningsoperasjoner',
    'disasterRelief.rel1desc': 'Profesjonelle oppblåsbare båter konstruert for søk- og redningsoppdrag over hele verden.',
    'disasterRelief.rel2': 'OEM/ODM-produksjon',
    'disasterRelief.rel2desc': 'Skreddersydd produksjon for humanitære organisasjoner med spesifikke oppdragskrav.',
    'disasterRelief.rel3': 'Kvalitet og testing',
    'disasterRelief.rel3desc': 'CE-sertifisert kvalitetsledelse som sikrer pålitelighet under ekstreme forhold.',
