    'learn.sup-size-guide.description': 'Comprehensive SUP sizing guide covering board length, width, thickness, volume, and rider weight matching.',
    'learn.sup-size-guide.title': 'SUP Size Guide',
    'learn.sup.description': 'Complete SUP knowledge hub covering beginner guides, board sizing, technique tutorials, safety tips, and inflatable SUP technology.',
